CREATE TABLE "User" ("id" TEXT NOT NULL PRIMARY KEY, "email" TEXT NOT NULL, "passwordHash" TEXT, "bufferCents" INTEGER NOT NULL DEFAULT 50000, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE UNIQUE INDEX "User_email_key" ON "User"("email");
CREATE TABLE "Account" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "name" TEXT NOT NULL, "type" TEXT NOT NULL, "balanceCents" INTEGER NOT NULL DEFAULT 0, CONSTRAINT "Account_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User" ("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE "Entry" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "accountId" TEXT NOT NULL, "name" TEXT NOT NULL, "type" TEXT NOT NULL, "amountCents" INTEGER NOT NULL, "category" TEXT NOT NULL, "scheduleJson" TEXT NOT NULL, "startDate" DATETIME NOT NULL, "endDate" DATETIME, "notes" TEXT, "isAuto" BOOLEAN NOT NULL DEFAULT false, "isVariable" BOOLEAN NOT NULL DEFAULT false, "skippedDatesJson" TEXT NOT NULL DEFAULT '[]', CONSTRAINT "Entry_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User" ("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "Entry_accountId_fkey" FOREIGN KEY ("accountId") REFERENCES "Account" ("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE "Debt" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "name" TEXT NOT NULL, "balanceCents" INTEGER NOT NULL, "aprBps" INTEGER NOT NULL, "minimumPaymentCents" INTEGER NOT NULL, "dueDay" INTEGER NOT NULL, CONSTRAINT "Debt_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User" ("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE "Goal" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "accountId" TEXT, "name" TEXT NOT NULL, "targetAmountCents" INTEGER NOT NULL, "currentSavedCents" INTEGER NOT NULL DEFAULT 0, "targetDate" DATETIME, CONSTRAINT "Goal_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User" ("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "Goal_accountId_fkey" FOREIGN KEY ("accountId") REFERENCES "Account" ("id") ON DELETE SET NULL ON UPDATE CASCADE);
CREATE TABLE "BankConnection" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "provider" TEXT NOT NULL, "externalItemId" TEXT, "status" TEXT NOT NULL DEFAULT 'MANUAL', "metadataJson" TEXT NOT NULL DEFAULT '{}', "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "ImportJob" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "sourceType" TEXT NOT NULL, "status" TEXT NOT NULL DEFAULT 'PENDING', "rawFileName" TEXT, "reportJson" TEXT NOT NULL DEFAULT '{}', "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
